const Aa = "/api",
	qj = new Map();
function eI(t, e) {
	if (typeof t?.message == "string" && t.message.trim()) return t.message;
	if (typeof t?._server_messages == "string")
		try {
			const s = JSON.parse(t._server_messages);
			if (Array.isArray(s) && s.length > 0) {
				const r = JSON.parse(s[0]);
				if (typeof r?.message == "string" && r.message.trim()) return r.message;
			}
		} catch {
			return e;
		}
	return e;
}
async function Ta(t) {
	if (!t.ok) {
		let e = `HTTP ${t.status}`;
		try {
			const s = await t.json();
			e = eI(s, e);
		} catch {}
		throw new Error(e);
	}
	try {
		return await t.json();
	} catch {
		return null;
	}
}
